// Normalize the Twilio payload. Twilio sends From=whatsapp:+919999000001 
// Strip the prefix, normalize phone.
const body = $input.first().json.body || $input.first().json;
const rawFrom = body.From || body.from || '';
const phone = rawFrom.replace(/^whatsapp:/, '').trim();
const text = body.Body || body.body || body.message || '';
const messageSid = body.MessageSid || body.message_sid || ('mock-' + Date.now());

if (!phone || !text) {
  return [{ json: { ok: false, error: 'Missing From or Body', phone, text } }];
}

const traceId = crypto.randomUUID();

return [{
  json: {
    phone,
    text,
    messageSid,
    receivedAt: new Date().toISOString(),
    traceId
  }
}];

// Determine if known lead. If unknown, end the flow (no ghost leads in v1.1).
const lookup = $input.first().json;
const rows = Array.isArray(lookup) ? lookup : (lookup.body && Array.isArray(lookup.body) ? lookup.body : []);
const hit = rows[0];
const norm = $('Code: Normalize Inbound').first().json;

if (!hit || !hit.existing_lead_id) {
  return [{ json: { ...norm, isKnown: false, leadId: null, leadName: null, currentStage: null, lastRescoredAt: null } }];
}

return [{
  json: {
    ...norm,
    isKnown: true,
    leadId: hit.existing_lead_id,
    leadName: hit.existing_name,
    currentScore: hit.existing_score,
    currentStage: hit.existing_stage
  }
}];

