// Parse Gemini extraction and merge with existing lead values WITHOUT clobbering.
// Honor the spec's rule: only fill nulls, never overwrite confirmed values.
const leadId = $('Code: Known or Unknown').first().json.leadId;
const geminiResp = $input.first().json;
let extracted = {};
try {
  const cand = geminiResp.body || geminiResp;
  const text = cand.candidates?.[0]?.content?.parts?.[0]?.text;
  if (text) extracted = JSON.parse(text);
} catch (e) {
  extracted = {};
}

const traceId = $('Code: Known or Unknown').first().json.traceId;

return [{
  json: {
    leadId,
    extracted,
    extractedCount: Object.keys(extracted).length,
    traceId
  }
}];

// Apply 5-minute debounce per lead (Open Q1 answered: 5min default)
const row = ($input.first().json[0] || $input.first().json || {});
const lastRescoredAt = row.last_rescored_at ? new Date(row.last_rescored_at).getTime() : 0;
const now = Date.now();
const DEBOUNCE_MS = 5 * 60 * 1000;

const shouldRescore = (now - lastRescoredAt) > DEBOUNCE_MS;
const leadId = $('Code: Parse Extracted Intent').first().json.leadId;
const traceId = $('Code: Parse Extracted Intent').first().json.traceId;
const extractedCount = $('Code: Parse Extracted Intent').first().json.extractedCount;

return [{
  json: {
    leadId,
    traceId,
    shouldRescore,
    debounceMsRemaining: shouldRescore ? 0 : DEBOUNCE_MS - (now - lastRescoredAt),
    extractedCount
  }
}];
